window.__QUIZ_DATA__=[{"id":"objective>Geography>1996>1","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question     The scale of the map, expressed as a statement is","images":["data:image/png;base64,"],"options":{"A":"1cm represent 1/4 km","B":"1cm represent 1/2 km","C":"1cm represent 50 mm","D":"1cm represent 50 m"},"answer":"B","explanation":"The representative fraction 1:50,000 on the map is the same as 2cm to1km in the the statement scale. 2cm to 1km is equivalent to 1cm to 1/2 km.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>2","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  The actual distance as the crow flies from Bo to Abe is","images":["data:image/png;base64,"],"options":{"A":"2.5km","B":"3.5km","C":"5.0km","D":"5.5km"},"answer":"A","explanation":"The actual distance as the crow flies from Bo to Abe is 2.5km","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>3","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  The feature marked S is","images":["data:image/png;base64,"],"options":{"A":"a lagoon","B":"a cliff","C":"a ria","D":"an estuary"},"answer":"D","explanation":"The feature marked S is an estuary. An estuary is the tidal mouth of a large river, where the tide meets the steam.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>4","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  The feature X can best be described as","images":["data:image/png;base64,"],"options":{"A":"an inselber","B":"a knoll","C":"a promontory","D":"a spur"},"answer":"B","explanation":"The feature X can best be described as a knoll . A knoll is an isolatedpeak of few metres high, associated with a highland.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>5","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  The eastern ridge may best be described as a","images":["data:image/png;base64,"],"options":{"A":"conical hill","B":"plateau","C":"watershed","D":"river capture"},"answer":"C","explanation":"The eastern ridge may best be described as a watershed. A watershed is a highland area which seperates the head streams of rivers flowing in different directions but arising from the same mountainous source.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>6","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  The direction of flow of River Buba is","images":["data:image/png;base64,"],"options":{"A":"North-west","B":"South-west","C":"North","D":"South"},"answer":"A","explanation":"The River Buba flows in the North-western direction.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>7","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  The predominant occupation of the people in the south-west of the map area is most likely to be","images":["data:image/png;base64,"],"options":{"A":"lumbering","B":"farming","C":"mining","D":"fishing"},"answer":"B","explanation":"The predominant occupation of the people in the south-west of the map area is farming due to the presence of farmlands.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>8","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  Fode may best be described as","images":["data:image/png;base64,"],"options":{"A":"a ferry point","B":"a river port","C":"a confluence town","D":"a route terminus"},"answer":"D","explanation":"Fode may best be described as a route terminus. A route terminus is the point where a transportation line or a travel route ends","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>9","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  Which of the following factors best explains the presence of marsh in the north-western part of the area?","images":["data:image/png;base64,"],"options":{"A":"Heavy rainfall","B":"River erosion","C":"Poor drainage","D":"Rise in sea level"},"answer":"C","explanation":"The presence of marsh in the north-western part of the area is due to poor drainage system.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>10","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : MAP WORK","question":"Use the map of GOMA DISTRICT to answer the question  The importance of Oje is best explained by its","images":["data:image/png;base64,"],"options":{"A":"location in a defensive site","B":"flood-free location","C":"trading activities","D":"Mineral workings"},"answer":"D","explanation":"Oje is important because of its mineral workings as shown on the map.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>11","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"Which of the following planets has the longest orbit around the sun?","images":[],"options":{"A":"Saturn","B":"Venus","C":"Mars","D":"Neptune"},"answer":"D","explanation":"Of the listed planets, Neptune the longest orbit around the sun. It takes about 164.8years to complete its orbit.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>12","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : PRINCIPLES OF ELEMENTARY SURVEYING","question":"A Great Circle can best be described as","images":[],"options":{"A":"a line of longitude","B":"the equator","C":"a circle on the globe whose plane passes through the poles","D":"the shortest distance between two points"},"answer":"D","explanation":"A Great Circle is any line that divides the earth in two equal halves or hemispheres. The shortest distance between two points on the earth's surface lies along the circumference of the great circle which passes these points.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>13","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"The axis of the earth is inclined to the plane of the ecliptic at an angle of","images":[],"options":{"A":"23(1/2)o","B":"66(1/2)o","C":"90o","D":"180o"},"answer":"B","explanation":"The axis of the earth is inclined to the plane of the ecliptic at an angle of 66(1/2)o","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>14","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"On September 23, all towns in the northern hemisphere experience","images":[],"options":{"A":"equal length of day and night","B":"longer days and shorter nights","C":"longer nights and shorter days","D":"complete darkness"},"answer":"A","explanation":"During equinoxes, all places on the earth have equal days and nights on these two days:  -March 21: it is called the Spring Equinox   -September 23: it is called the Autumn Equinox","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>15","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"The density of the upper part of the lithosphere","images":[],"options":{"A":"1.2","B":"1.7","C":"2.0","D":"2.7"},"answer":"D","explanation":"The upper part of the lithosphere consists of granite rocks and forms the continent. The upper earth crust has an average density of 2.7.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>16","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ROCKS","question":"Grit is a good example of","images":[],"options":{"A":"plutonic igneous rock","B":"volcanic igneous rock","C":"organically formed sedimentary rock","D":"mechanically formed sedimentary rock"},"answer":"D","explanation":"Grit is a mechanically formed sedimentary rock. It is formed from sediments of other rocks that have acccumulated and cemented together over a long period of time. Other examples are clay, shale, breccia etc.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>17","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Crater lakes are most likely to occur in","images":[],"options":{"A":"areas of active erosion.","B":"regions where subsidence is taking place","C":"regions of extinct volcanoes","D":"heavily faulted regions"},"answer":"C","explanation":"One of the extrusive land forms of vulcanicity is the cinder cone. Cinder cones are formed from less fluid acid lava, containing cinder ash, rock fragments and lava bombs. The lava flows are viscous and they solidify after a short distance. At times, the lava closes the vent and this results in an explosion which blows the vent open. After the explosion, a crater which is a depression on the top of the cone is formed. If water occupies the crater, it becomes a crater lake. Hence, a crater lake is most likely to occur in regions of extinct volcanoes.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>18","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : DENUDATIONAL PROCESSES","question":"Yardangs are best described as","images":[],"options":{"A":"long narrow ridges of sand lying parallel to the direction of the prevailing winds","B":"steep-sided vertical bands of alternate hard and soft rocks aligned in the direction of the prevailing winds","C":"flat, table-like masses with very resistant horizontal top layers and very steep sides","D":"tabular, horizontal strata of alternate hard and soft rocks sculptured into a ridge and furrow landscape by wind"},"answer":"B","explanation":"Yardangs are vertical bands of hard and soft rocks, ridge and furrow of landscape of about 10-15 metres long. Yardangs are formed when hard and soft rocks in vertical bands are aligned in the direction of the prevailing winds.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>19","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The seasonal variation in the volume of water in a river is known as its","images":[],"options":{"A":"direction","B":"load","C":"velocity","D":"regime"},"answer":"D","explanation":"The seasonal variation in the volume of water in a river is known as its regime. The river regime refers to the variability in the discharge of the river through the course of a year in response to precipitation, temperature, evaporation and drainage basin characteristics.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>20","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The predominant action at the upper course of a river is","images":[],"options":{"A":"saltation","B":"transportation","C":"deposition","D":"corrasion"},"answer":"D","explanation":"The predominant action at the upper course of a river is corrasion. Corrasion is the wearing away of the side and floor of the river valley with the aid of sand pebbles, silts and boulders which are being transported","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>21","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The word shore is best described as the zone between high and low water levels at the coast.","images":[],"options":{"A":"which extends from the coastline to the sea","B":"between high and low water levels at the coast.","C":"that marks the seaward limit of the coast","D":"extending under the shallow waters of the sea"},"answer":"B","explanation":"The word shore is best described as the zone between high and low water levels at the coast. This is the area that is exposed to the air at low tide and submerged at high tide. It is the area between the highest level of wave action at high tide and the lowest tide level.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>22","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : HYDROSPHERE","question":"The delta of the River Nile is best described as","images":[],"options":{"A":"bird's foot","B":"estuarine","C":"arcuate","D":"cuspate"},"answer":"C","explanation":"An arcuate delta consists of both coarse and fine sediments and has the shape of an inverted cone. It is crossed by many distributaries. Examples are found in Niger, Nile, the Ganges, the Indus, the Mekong and Hwang Ho deltas.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>23","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : SOIL","question":"Which of the following soils is easily water-logged?","images":[],"options":{"A":"Sandy soil","B":"Clayey soil","C":"Loamy soil","D":"Lateritic soil"},"answer":"B","explanation":"Clayey soil is easily water-logged. This is because clay particles are very small and tightly packed together, which reduces the space between them. This makes it difficult for water to drain through, leading to water-logging.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>24","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ENVIRONMENTAL RESOURCES","question":"The green plants which serve as producer to other organisms in the ecosystem are called","images":[],"options":{"A":"autotrophs","B":"heterotrophs","C":"decomposers","D":"biota"},"answer":"A","explanation":"The green plants which serve as producer to other organisms in the ecosystem are known as autotrophs because they manufacture their food by themselves.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1996>25","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"A major characteristic of the tropical woodland vegetation is that","images":[],"options":{"A":"it consists of grass and shrubs only","B":"the forest consists of scattered trees only","C":"it consists mainly of mangroves","D":"its open forest permits the growth of grass"},"answer":"D","explanation":"Tropical woodland vegetation, also known as savanna, is characterized by a mixture of trees and grasses. The trees are scattered and do not form a closed canopy, allowing sunlight to reach the ground and support the growth of grasses. Therefore, the statement 'its open forest permits the growth of grass' is correct.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>26","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"The Westerlies and the North-East Trade Winds are similar because they both","images":[],"options":{"A":"originate from the Horse Latitudes of the northern hemisphere","B":"blow towards the temperate low pressure belt of the northen hemisphere","C":"converge at the doldrums in summer","D":"carry moisture to the coasts of Europe in summer"},"answer":"B","explanation":"The Westerlies and the North-East Trade Winds blow towards the temperate low pressure belt of the northen hemisphere","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>27","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"If left in the open, wet clothes take a longer time to dry when","images":[],"options":{"A":"relative humidity is high","B":"pressure is low.","C":"relative humidity is low","D":"clouds are slow-moving"},"answer":"A","explanation":"Relative humidity is a measure of the amount of moisture in the air compared to the maximum amount the air could hold at the same temperature. When relative humidity is high, it means the air is nearly saturated with moisture, so it has less capacity to absorb more moisture from wet clothes. Therefore, wet clothes take a longer time to dry when relative humidity is high.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>28","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Visibility usually decreases when a","images":[],"options":{"A":"cold, dry wind blows over a cold current","B":"body of fresh water mingles with salty water","C":"warm wind blows over a warm current","D":"warm dry wind rises over a high mountain"},"answer":"C","explanation":"Whenever a warm wind blows over a warm current, visibility always decreases","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>29","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"Diurnal range of temperature is the difference between the","images":[],"options":{"A":"highest and the lowest temperature recorded in a station every year","B":"highest and the lowest temperature recorded in a station everyday","C":"highest and the lowest temperatures recorded in a station every month","D":"readings of the wet bulb and the dry bulb thermometers"},"answer":"B","explanation":"Diurnal range of temperature= Highest Temperature in a day - Lowest Temperature in a day   Diurnal range of temperature is the difference between the highest and the lowest temperature recorded in a station everyday","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>30","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : WEATHER AND CLIMATE","question":"They are tropical and subtropical storms, occurring over land, they are funnel-shaped and violent, with winds of high velocity reaching up to 330kmph, which of the following winds is described above?","images":[],"options":{"A":"Chinook","B":"Hurricane","C":"Typhoon","D":"Tornado"},"answer":"D","explanation":"Tornadoes are found in Guinea lands of west Africa and the southern U.S.A, where they are whirlwind and in N.W. Australia where they are called willy-willies. They are small, but very violent tropical and sub-tropical cyclones with a speed of 800km/hour. They are most frequent in spring but can also occur at almost any time. They have a dark funnel cloud 80-400 metres in diameter and are very destructive.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>31","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : WORLD POPULATION","question":"Which of the following population variable is not calculated in unit per thousand?","images":[],"options":{"A":"Birth rate","B":"Death rate","C":"Fertility rate","D":"Migration rate"},"answer":"D","explanation":"The migration rate of a country is not calculated in unit per thousand","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>32","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : SETTLEMENT","question":"Which of the following least influences the growth of settlements?","images":[],"options":{"A":"Age","B":"Climate","C":"Mineral resources","D":"Relief"},"answer":"A","explanation":"Age least influences the growth of settlements. The growth of settlements is primarily influenced by factors such as availability of resources, climate, relief, and human activities such as trade. The age of the settlement or the people within it has little to no influence on its growth.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>33","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following industries is always located at the source of its major raw materials?","images":[],"options":{"A":"Automobile","B":"Cement","C":"Brewery","D":"Textile"},"answer":"B","explanation":"Cement industry is always located at the source of its major raw materials. The cement industry requires bulky and heavy raw materials like limestone, silica, alumina, and gypsum. The cost of transporting these materials can be quite high, so cement plants are usually located near the source of raw materials.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>34","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"which of the following is a disadvantage of water transport? It","images":[],"options":{"A":"causes atmospheric pollution","B":"is used for carrying agricultural commodities only","C":"is not flexible","D":"is not suitable for international trade"},"answer":"C","explanation":"A disadvantage of water transport is that it is not flexible. It cannot be adjusted to individual requirements.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>35","subject":"Geography","year":"1996","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"One important consequence of the location of Nigeria between latitudes 40 and 140 North of the equator is that","images":[],"options":{"A":"some parts of the country enjoy a hot, wet, tropical climate throughout the year","B":"the south westerly winds blow only across the coastal areas","C":"all parts of country receive rainfall throughout the year","D":"all part of the country have a luxuriant vegetation"},"answer":"A","explanation":"One important consequence of the location of Nigeria between latitudes 40 and 140 North of the equator is that some parts of the country enjoy a hot, wet, tropical climate throughout the year","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>36","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRANSPORTATION","question":"A specialized mode of transportation used in carrying coal from Enugu to Oji River is the","images":[],"options":{"A":"pipeline","B":"transmission line","C":"rope way","D":"rail cart"},"answer":"D","explanation":"The rail cart is a type of rail road freight car used to transport loose bulk commodities such as coal.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>37","subject":"Geography","year":"1996","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : PHYSICAL SETTING","question":"Which of the geographical regions of Nigeria contains volcanic plugs, inselbergs and crater lake?","images":[],"options":{"A":"Eastern scarplands","B":"Western highlands","C":"North-central highland","D":"Eastern highlands"},"answer":"C","explanation":"The North-central highlands is found in the centre of the Northern Nigeria. It consists of two levels; the high plains of Hausaland(750m) and Jos plateau(1500-1800m). It is an area of intensive volcanic activities, hence, it contains volcanic plugs, inselbergs and crater lake.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>38","subject":"Geography","year":"1996","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : INDUSTRY","question":"The location of the oil refinery at Kaduna is best explained by the","images":[],"options":{"A":"deliberate government policy and market","B":"presence of power supply and market","C":"availability of raw material and capital","D":"adequate transportation and labour"},"answer":"A","explanation":"The location of the oil refinery at Kaduna is best explained by the deliberate government policy and market. The government policy was to decentralize the oil industry and bring development to different parts of the country. The market refers to the demand for petroleum products in the northern part of Nigeria which Kaduna refinery serves.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>39","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"All the following statements are true of the savanna vegetation in Nigeria except that the","images":[],"options":{"A":"trees are deciduous","B":"trees have thick water-storing trunks","C":"trees have long tap root systems","D":"trees occur in the pure stands"},"answer":"D","explanation":"In the savanna vegetation of Nigeria, trees do not occur in pure stands. A pure stand is a stand of trees of the same species. In the savanna, the vegetation is a mixture of grasses and trees of different species.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>40","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"A major characteristic of local craft industry is that","images":[],"options":{"A":"it requires a specially built factory","B":"it is mainly hereditry","C":"it requires a large labour force","D":"its products are used by other industries"},"answer":"B","explanation":"local craft industries make use of a small space as their workshop, they are mainly hereditary, they do not require a large force, they depend on raw materials obtained from their immediate locality, they use simple tools and their work is of high artistic quality.","marks":"1","difficulty":"1"},{"id":"objective>Geography>1996>41","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : ELEMENTS OF PHYSICAL GEOGRAPHY","question":"In Africa coral reef coasts are largely located in the","images":[],"options":{"A":"north-west","B":"south-west","C":"west","D":"south"},"answer":"A","explanation":"coral reef coasts are largely located in the North-western region of Africa.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>42","subject":"Geography","year":"1996","type":"Objective","topic":"ELEMENTS OF PRACTICAL AND PHYSICAL GEOGRAPHY : VEGETATION","question":"Which of the following vegetation types is most common in Africa?","images":[],"options":{"A":"Steppe","B":"Campos","C":"Selvas","D":"Savanna"},"answer":"D","explanation":"The savanna is the most common vegetation type in Africa. It occupies almost 65% of Africa. The largest areas of savanna are found in Africa, south America, Australia, India, Madagascar e.t.c.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>43","subject":"Geography","year":"1996","type":"Objective","topic":"REGIONAL GEOGRAPHY OF AFRICA : AFRICA ON BROAD OUTLINE","question":"In Africa, the veldt is located in the","images":[],"options":{"A":"western coastland","B":"eastern coastland","C":"continental interior","D":"southern part"},"answer":"D","explanation":"In Africa veldt refers to the elevated, flat and often treeless plateaus found in southern Africa, most notably in south Africa and Zimbabwe","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>44","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Africa has the largest potential reserves of hydro-electric power in the world due to","images":[],"options":{"A":"its many plateaus","B":"its high demand for power","C":"the abundant rainfall and waterfalls there","D":"the presence of very long rivers"},"answer":"C","explanation":"Due to abundance of rainfall and waterfalls in the African continent, it has the largest potential reserves of hydro-electric power in the world.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>45","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : TRADE","question":"The low level of trade among West African countries is mainly because","images":[],"options":{"A":"of mistrust among them","B":"of the language barrier","C":"there is a well developed transport network","D":"they produce similar goods"},"answer":"D","explanation":"Due to the production of similar goods by west African countries, there exist a low volume of trade between them","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>46","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"The basin system of irrigation in the Nile Basin is not reliable because","images":[],"options":{"A":"too much of the water percolates into the ground","B":"only a few crops can be grown","C":"it is not considered suitable by some farmers","D":"it depends on the flow of the Nile in a particular year"},"answer":"D","explanation":"Irrigation is mainly pratised in areas where there is insufficient rainfall like in Egypt and sudan(Nile Basin) which make use of water from the River Nile. The Basin system of irrigation in the Nile Basin is not reliable because it depends on the flow of the Nile in a particular year.","marks":"1","difficulty":"3"},{"id":"objective>Geography>1996>47","subject":"Geography","year":"1996","type":"Objective","topic":"ECONOMIC AND HUMAN GEOGRAPHY : INDUSTRY","question":"Which of the following represents the first stage in the lumbering process?","images":[],"options":{"A":"Trees are felled","B":"Platforms are built for buttress trees","C":"Particular species are identified","D":"Trees are cut into logs"},"answer":"C","explanation":"The first stage in the lumbering process is identifying the particular species of trees to be cut down. This is important because different species of trees have different uses and values. Therefore, lumberjacks need to know which species they are dealing with before they start the felling process.","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>48","subject":"Geography","year":"1996","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"The Muturu type of cattle is reared mainly in the western highland region of Nigeria because","images":[],"options":{"A":"it has no hump","B":"of the harsh weather of the North-central highlands","C":"it is resistant to tsetse flies","D":"of the luxuriant pasture there"},"answer":"C","explanation":"The Muturu type of cattle is reared mainly in the western highland region of Nigeria because it is resistivity to tsetse flies","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>49","subject":"Geography","year":"1996","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Monoculture is a term associated with","images":[],"options":{"A":"livestock farming","B":"arable farming","C":"mixed farming","D":"plantation agriculture"},"answer":"D","explanation":"Monoculture  involves the cultivation of a single crop on a large piece of land. It is associated with plantation agriculture","marks":"1","difficulty":"2"},{"id":"objective>Geography>1996>50","subject":"Geography","year":"1996","type":"Objective","topic":"REGIONAL GEOGRAPHY OF NIGERIA : AGRICULTURE","question":"Some plant diseases are checked during the fallow periods in the bush fallowing system of agriculture because the","images":[],"options":{"A":"humus accumulates over time","B":"fires used in clearing the bush destroy them","C":"plant species resist the diseases","D":"disease organisms lose their hosts and die"},"answer":"D","explanation":"One of the advantages of bush fallowing system of agriculture is that it helps to control plant diseases and pests. This is because during the fallow periods, disease organisms lose their hosts and die.","marks":"1","difficulty":"2"}];